import React, { useState, useEffect } from 'react';
import { useProducts } from '../context/ProductContext';
import SearchBar from './SearchBar';
import EditablePriceTable, {
    Product as TableProduct,
} from './EditablePriceTable';
import './PriceManagementPage.css';

export default function PriceManagementPage() {
    const { products, updateProductPrice, deleteProduct } = useProducts();
    const [searchResults, setSearchResults] = useState<TableProduct[]>([]);

    // whenever products change, map them into TableProduct and reset both table & search
    useEffect(() => {
        const tableData = products.map(p => ({
            id: p.id,
            name: p.name,
            currentPrice: p.price,
        }));
        setSearchResults(tableData);
    }, [products]);

    const handleSearch = (q: string) => {
        const lower = q.toLowerCase();
        setSearchResults(
            !lower
                ? products.map(p => ({
                    id: p.id,
                    name: p.name,
                    currentPrice: p.price,
                }))
                : products
                    .filter(p => p.name.toLowerCase().includes(lower))
                    .map(p => ({
                        id: p.id,
                        name: p.name,
                        currentPrice: p.price,
                    }))
        );
    };

    const handleUpdate = (id: number, newPrice: number) => {
        updateProductPrice(id, newPrice);
    };

    return (
        <div className="price-management-container">
            <h2>Real-Time Pricing</h2>
            <SearchBar onSearch={handleSearch} placeholder="Ürün ara…" />

            <EditablePriceTable
                products={searchResults}
                onPriceUpdate={handleUpdate}
                onDelete={deleteProduct}
                validationFn={price => price > 0}
            />
        </div>
    );
}
